class CreditCardEncryption:
    def __init__(self, config):
        self.config = config
        self.key = self._get_or_create_key()
        self.cipher_suite = Fernet(self.key)
    
    def _get_or_create_key(self):
        """Get encryption key from config or generate new one"""
        if 'encryption_key' in self.config:
            return base64.urlsafe_b64encode(self.config['encryption_key'].ljust(32)[:32].encode())
        else:
            # Generate new key and store it in config
            key = Fernet.generate_key()
            self.config['encryption_key'] = key.decode()
            return key
    
    def encrypt_card_number(self, card_number):
        """Encrypt credit card number"""
        if not isinstance(card_number, str):
            raise ValueError("Card number must be a string")
        
        # Remove spaces and dashes for validation
        clean_number = card_number.replace(' ', '').replace('-', '')
        
        # Basic validation
        if not clean_number.isdigit() or len(clean_number) < 13 or len(clean_number) > 19:
            raise ValueError("Invalid card number format")
        
        encrypted = self.cipher_suite.encrypt(card_number.encode())
        return base64.urlsafe_b64encode(encrypted).decode()
    
    def decrypt_card_number(self, encrypted_card_number):
        """Decrypt credit card number"""
        try:
            encrypted_data = base64.urlsafe_b64decode(encrypted_card_number.encode())
            decrypted = self.cipher_suite.decrypt(encrypted_data)
            return decrypted.decode()
        except Exception as e:
            raise ValueError("Decryption failed: " + str(e))

